func NoopAuditFactory(records **[][]byte, useEventLogger bool) audit.Factory {
	return func(_ context.Context, config *audit.BackendConfig, useEventLogger bool) (audit.Backend, error) {
		n, err := NewNoopAudit(config.Config, useEventLogger)
		if err != nil {
			return nil, err
		}
		if records != nil {
			*records = &n.records
		}
		return n, nil
	}
}

